               )}
            </div>
         )}
      </div>

      {/* Floating Chatbot Overlay */}
      {chatContext && (
          <InsightChatbot 
              contextData={chatContext} 
              onClose={() => setChatContext(null)} 
          />
      )}
    </div>
  );
};

export default TrackingDashboard;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Loader2, RefreshCw, MessageSquare, Check, LayoutGrid, List, ChevronDown, ChevronLeft, ChevronRight } from 'lucide-react';
import { TrackedItem } from '../../services/trackingStorage';
import { initiateBulkInsightExtraction, pollBulkInsightStatus, fetchStockSecInfo } from '../../services/dataService';
import { PollStatusResponse, InsightResultItem } from '../../types/trackingTypes';
import { processRawInsightData } from '../../services/geminiService';
import { getTopElementInnerHTML} from '../../services/helper.ts';

// Import Card Components
import BaseInsightCard from './cards/BaseInsightCard';
import PECard from './cards/PECard';
import DetailedPECard from './cards/DetailedPECard';
import MFHoldingsCard from './cards/MFHoldingsCard';
import QuarterlyHoldingsCard from './cards/QuarterlyHoldingsCard';
import BulkBlockDealsCard from './cards/BulkBlockDealsCard';
import InsiderDealsCard from './cards/InsiderDealsCard';
import TechnicalCard from './cards/TechnicalCard';
import FinancialsCard from './cards/FinancialsCard';
import DefaultInsightCard from './cards/DefaultInsightCard';

interface BulkInsightManagerProps {
  items: TrackedItem[];
  // State lifted to parent
  results: Record<string, InsightResultItem[]>;
  setResults: React.Dispatch<React.SetStateAction<Record<string, InsightResultItem[]>>>;
  status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
  setStatus: React.Dispatch<React.SetStateAction<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>>;
  progress: { completed: number; total: number };
  setProgress: React.Dispatch<React.SetStateAction<{ completed: number; total: number }>>;
  requestId: string | null;
  setRequestId: React.Dispatch<React.SetStateAction<string | null>>;
  onOpenChat: (context: any[]) => void;
  onSelectStock: (symbol: string, name: string) => void;
}

// --- MultiSelect Component ---
interface MultiSelectProps {
    label: string;
    options: string[];
    selected: string[];
    onChange: (selected: string[]) => void;
}

const MultiSelect: React.FC<MultiSelectProps> = ({ label, options, selected, onChange }) => {
    const [isOpen, setIsOpen] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);

    const toggleOption = (option: string) => {
        if (selected.includes(option)) {
            onChange(selected.filter(s => s !== option));
        } else {
            onChange([...selected, option]);
        }
    };

    return (
        <div className="relative flex-1 min-w-[140px]" ref={containerRef}>
            <button
                onClick={() => setIsOpen(!isOpen)}
                className="flex items-center justify-between w-full bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg px-3 py-2 hover:bg-white hover:border-gray-300 transition-colors"
            >
                <span className="truncate">
                    {selected.length === 0 ? `All ${label}` : `${selected.length} ${label}`}
                </span>
                <ChevronDown size={14} className="text-gray-400 ml-2" />
            </button>

            {isOpen && (
                <div 
                    className="absolute top-full left-0 right-0 mt-1 bg-white border border-gray-200 rounded-lg shadow-lg z-50 max-h-60 overflow-y-auto p-1"
                    onMouseDown={(e) => e.stopPropagation()} 
                >
                    <div 
                        onClick={() => onChange([])}
                        className={`px-3 py-2 text-sm rounded-md cursor-pointer hover:bg-indigo-50 flex items-center justify-between ${selected.length === 0 ? 'bg-indigo-50 text-indigo-700 font-medium' : 'text-gray-700'}`}
                    >
                        <span>All {label}</span>
                        {selected.length === 0 && <Check size={14} />}
                    </div>
                    {options.map(opt => (
                        <div 
                            key={opt}
                            onClick={() => toggleOption(opt)}
                            className={`px-3 py-2 text-sm rounded-md cursor-pointer hover:bg-gray-50 flex items-center justify-between ${selected.includes(opt) ? 'bg-gray-50 text-gray-900 font-medium' : 'text-gray-600'}`}
                        >
                            <span className="truncate mr-2">{opt}</span>
                            {selected.includes(opt) && <Check size={14} className="text-indigo-600 flex-shrink-0" />}
                        </div>
                    ))}
                </div>
            )}
        </div>
    );
};

const BulkInsightManager: React.FC<BulkInsightManagerProps> = ({ 
  items, 
  results, 
  setResults, 
  status, 
  setStatus, 
  progress, 
  setProgress, 
  requestId, 
  setRequestId,
  onOpenChat,
  onSelectStock
}) => {

  // Local UI State
  const [selectedCards, setSelectedCards] = useState<Set<string>>(new Set());

  // Multi-select filters (empty array means ALL)
  const [filterSymbols, setFilterSymbols] = useState<string[]>([]);
  const [filterIndicators, setFilterIndicators] = useState<string[]>([]);

  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const [pageSize, setPageSize] = useState(50);

  // Track ongoing Gemini processing to prevent duplicate calls
  const processingRef = useRef<Set<string>>(new Set());

  // Reset pagination when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [filterSymbols, filterIndicators]);

  // --- Actions ---

  const startExtraction = async () => {
    setResults({});
    const stockSymbols = items.filter(i => i.type === 'STOCK').map(i => i.id);
    if (stockSymbols.length === 0) return;

    setStatus('initializing');
    setProgress({ completed: 0, total: stockSymbols.length });

    // Clear old requestId to stop any previous polling
    setRequestId(null); 
    // Clear processing cache to allow re-parsing on fresh fetch
    processingRef.current.clear();

    const response = await initiateBulkInsightExtraction(stockSymbols);

    if (response && response.requestId) {
      setRequestId(response.requestId);
      setStatus('polling');
      setProgress({ completed: 0, total: response.totalStocks });
    } else {
      setStatus('error');
    }
  };

  // --- Auto Fetch Logic ---
  useEffect(() => {
    const stockItems = items.filter(i => i.type === 'STOCK');
    const hasItems = stockItems.length > 0;

    // Check if we are missing results for any tracked stock
    const missingResults = stockItems.some(i => !results[i.id] || results[i.id].length === 0);

    const shouldFetch = hasItems && 
                        status !== 'polling' && 
                        status !== 'initializing' &&
                        (status === 'idle' || missingResults);

    if (shouldFetch) {
        startExtraction();
    }
  }, [items, status, results]); 

  // --- Polling Logic ---
  useEffect(() => {
    let intervalId: ReturnType<typeof setInterval>;

    const poll = async () => {
      if (!requestId || status !== 'polling') return;

      const data = await pollBulkInsightStatus(requestId);

      if (data) {
        setProgress({ completed: data.completedStocks, total: data.totalStocks });
        handleNewResults(data);

        if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks === data.totalStocks)) {
          setStatus('completed');
          setRequestId(null);
        }
      }
    };

    if (status === 'polling') {
      poll();
      intervalId = setInterval(poll, 5000);
    }

    return () => clearInterval(intervalId);
  }, [requestId, status]);

  const handleNewResults = (data: PollStatusResponse) => {
    setResults(prev => {
      const next = { ...prev };
      // Deep merge logic
      for (const [symbol, val] of Object.entries(data.results)) {
        const newItems = val as InsightResultItem[];
        const existingItems = next[symbol] || [];
        const mergedItems = [...existingItems];
        newItems.forEach(newItem => {
           const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
           if (index > -1) {
               const existing = mergedItems[index];

               // CRITICAL FIX: Do not overwrite parsed JSON with raw HTML string from polling
               // If existing is JSON and new is string, keep existing data but update other fields if needed.
               if (existing.type === 'json' && typeof newItem.data === 'string') {
                   mergedItems[index] = {
                       ...newItem,
                       data: existing.data, // Preserve parsed JSON
                       type: existing.type
                   };
               } else {
                   mergedItems[index] = newItem;
               }
           } else {
               mergedItems.push(newItem);
           }
        });
        next[symbol] = mergedItems;
      }
      return next;
    });
  };

  // --- Gemini Processing Logic for HTML Content ---
  useEffect(() => {
    Object.entries(results).forEach(([symbol, items]) => {
      (items as InsightResultItem[]).forEach(async (item) => {
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        // If item requires parsing, is raw HTML string, matches simple HTML check, and isn't processing
        if (item.geminiParsingReq && 
            item.success && 
            typeof item.data === 'string' && 
            item.data.trim().startsWith('<') &&
            !processingRef.current.has(uniqueKey)
        ) {
            processingRef.current.add(uniqueKey);

            try {
                // Call Parsing Service (Refactored to local DOM parsing)
                let dataToParse = item.data;
                if(item.indicatorName === "Insider/SAST Deals") {
                  dataToParse = getTopElementInnerHTML(item.data);
                }

                const jsonStr = await processRawInsightData(dataToParse, item.geminiPrompt, item.indicatorName);

                let jsonObj;
                try {
                    jsonObj = JSON.parse(jsonStr);
                    // MERGE NSE DATA FOR PE CARD (Fix for Tracked Assets view)
                    if (item.indicatorName === 'PE') {
                         try {
                             const secInfo = await fetchStockSecInfo(symbol);
                             if (secInfo) {
                                 jsonObj.secInfo = secInfo;
                             }
                         } catch(e) {
                             console.warn(`Failed to fetch NSE SecInfo for ${symbol}`, e);
                         }
                    }
                } catch(e) {
                    jsonObj = { error: "Failed to parse data output", raw: jsonStr };
                }

                // Update State with JSON data
                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: jsonObj,
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            } catch (err) {
                console.error("Processing failed for", uniqueKey);
                // Mark as failed state so we don't retry continuously
                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: { error: "Processing failed" },
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            }
        }
      });
    });
  }, [results]);

  // --- Selection Logic ---

  const toggleCardSelection = (symbol: string, indicator: string) => {
      const key = `${symbol}|${indicator}`;
      const newSet = new Set(selectedCards);
      if (newSet.has(key)) newSet.delete(key);
      else newSet.add(key);
      setSelectedCards(newSet);
  };

  const handleAnalyzeSelection = () => {
      const selectedData: any[] = [];
      selectedCards.forEach(key => {
          const [sym, ind] = key.split('|');
          const item = results[sym]?.find(i => i.indicatorName === ind);
          if (item) {
              selectedData.push({ symbol: sym, indicator: ind, data: item.data });
          }
      });
      if (selectedData.length > 0) onOpenChat(selectedData);
  };

  const getStockName = (sym: string) => {
      const item = items.find(i => i.id === sym);
      return item ? item.name : sym;
  };

  // --- Render Factory ---

  const renderSpecificCard = (indicator: string, data: any) => {
      switch(indicator) {
          case 'PE':
              return <PECard data={data} />;
          case 'DetailledPE':
              return <DetailedPECard data={data} />;
          case 'MFHoldings':
              return <MFHoldingsCard data={data} />;
          case 'QuaterlyHoldings':
              return <QuarterlyHoldingsCard data={data} />;
          case 'Bulk/Block Deals':
              return <BulkBlockDealsCard data={data} />;
          case 'Insider/SAST Deals':
              return <InsiderDealsCard data={data} />;
          case 'Technical':
              return <TechnicalCard data={data} />;
          case 'FinancialInsights':
              return <FinancialsCard data={data} />;
          default:
              return <DefaultInsightCard data={data} />;
      }
  };

  const flatItems = useMemo(() => {
      const flat: Array<{ symbol: string; item: InsightResultItem }> = [];
      Object.entries(results).forEach(([symbol, val]) => {
          const indicators = val as InsightResultItem[];
          if (filterSymbols.length > 0 && !filterSymbols.includes(symbol)) return;

          indicators.forEach(item => {
              if (filterIndicators.length > 0 && !filterIndicators.includes(item.indicatorName)) return;
              flat.push({ symbol, item });
          });
      });
      return flat;
  }, [results, filterSymbols, filterIndicators]);

  // --- Pagination Slice ---
  const paginatedItems = useMemo(() => {
    const startIndex = (currentPage - 1) * pageSize;
    return flatItems.slice(startIndex, startIndex + pageSize);
  }, [flatItems, currentPage, pageSize]);

  const totalPages = Math.ceil(flatItems.length / pageSize);

  const uniqueSymbols = Object.keys(results);
  const uniqueIndicators = Array.from(new Set((Object.values(results).flat() as InsightResultItem[]).map(i => i.indicatorName)));

  if (items.filter(i => i.type === 'STOCK').length === 0) return null;

  return (
    <div className="space-y-4">
      {/* Control Bar */}
      <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col xl:flex-row items-center justify-between gap-4 shadow-sm z-30 relative">
         <div className="flex flex-col md:flex-row items-start md:items-center gap-4 w-full xl:w-auto">

             {/* Left Group: View & Filters */}
             <div className="flex items-center gap-4 w-full md:w-auto">
                {/* View Toggle */}
                <div className="flex bg-gray-100 p-1 rounded-lg shrink-0">
                  <button 
                      onClick={() => setViewMode('grid')}
                      className={`p-1.5 rounded-md transition-all ${viewMode === 'grid' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                      title="Grid View"
                  >
                    <LayoutGrid size={16} />
                  </button>
                  <button 
                      onClick={() => setViewMode('list')}
                      className={`p-1.5 rounded-md transition-all ${viewMode === 'list' ? 'bg-white shadow-sm text-indigo-600' : 'text-gray-500 hover:text-gray-700'}`}
                      title="List View"
                  >
                    <List size={16} />
                  </button>
                </div>

                <div className="h-6 w-px bg-gray-200 mx-1 hidden md:block"></div>

                {/* Multi-Select Filters */}
                <div className="flex gap-2 w-full md:w-auto flex-wrap">
                    <MultiSelect 
                        label="Stocks" 
                        options={uniqueSymbols} 
                        selected={filterSymbols} 
                        onChange={setFilterSymbols} 
                    />

                    <MultiSelect 
                        label="Indicators" 
                        options={uniqueIndicators} 
                        selected={filterIndicators} 
                        onChange={setFilterIndicators} 
                    />
                </div>
             </div>

             {/* Pagination Controls */}
             {flatItems.length > 0 && (
                <div className="flex items-center gap-3 pl-0 md:pl-4 md:border-l border-gray-200 w-full md:w-auto justify-between md:justify-start">
                    <div className="flex items-center gap-2">
                      <span className="text-xs text-gray-500 font-medium">Rows:</span>
                      <select 
                        value={pageSize} 
                        onChange={(e) => { setPageSize(Number(e.target.value)); setCurrentPage(1); }}
                        className="bg-gray-50 border border-gray-200 text-gray-700 text-xs rounded-lg p-1.5 focus:ring-indigo-500 focus:border-indigo-500"
                      >
                        <option value={10}>10</option>
                        <option value={20}>20</option>
                        <option value={50}>50</option>
                        <option value={100}>100</option>
                      </select>
                    </div>

                    <div className="flex items-center gap-2">
                        <button
                          onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                          disabled={currentPage === 1}
                          className="p-1.5 rounded-md bg-gray-50 text-gray-600 border border-gray-200 hover:bg-white hover:border-indigo-300 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                           <ChevronLeft size={14} />
                        </button>
                        <span className="text-xs text-gray-600 font-medium whitespace-nowrap min-w-[60px] text-center">
                          {currentPage} / {totalPages}
                        </span>
                        <button
                          onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                          disabled={currentPage === totalPages}
                          className="p-1.5 rounded-md bg-gray-50 text-gray-600 border border-gray-200 hover:bg-white hover:border-indigo-300 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                        >
                           <ChevronRight size={14} />
                        </button>
                    </div>
                </div>
             )}
         </div>

         {/* Right Group: Actions */}
         <div className="flex items-center gap-3 w-full xl:w-auto justify-end border-t xl:border-t-0 border-gray-100 pt-3 xl:pt-0">
             {selectedCards.size > 0 && (
                 <button 
                    onClick={handleAnalyzeSelection}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-lg hover:bg-indigo-700 transition-colors shadow-sm whitespace-nowrap"
                 >
                     <MessageSquare size={16} />
                     Analyze Selected ({selectedCards.size})
                 </button>
             )}

            {status === 'polling' || status === 'initializing' ? (
                <div className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-700 rounded-lg text-sm whitespace-nowrap">
                    <Loader2 size={16} className="animate-spin" />
                    <span>
                      {status === 'initializing' ? 'Initializing...' : `${progress.completed}/${progress.total}`}
                    </span>
                </div>
            ) : (
                <button 
                    onClick={startExtraction}
                    className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-gray-100 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                    title="Refresh Data"
                >
                    <RefreshCw size={20} />
                </button>
            )}
         </div>
      </div>

      {/* Loading Skeleton */}
      {flatItems.length === 0 && (status === 'initializing' || status === 'polling') && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 animate-pulse">
             {[...Array(6)].map((_, i) => (
                 <div key={i} className="bg-white rounded-xl border border-gray-100 p-4 h-40 flex flex-col justify-between">
                    <div className="flex justify-between items-center mb-4">
                        <div className="h-4 bg-gray-200 rounded w-1/3"></div>
                        <div className="h-4 bg-gray-200 rounded w-4"></div>
                    </div>
                    <div className="space-y-2">
                        <div className="h-3 bg-gray-100 rounded w-full"></div>
                        <div className="h-3 bg-gray-100 rounded w-5/6"></div>
                        <div className="h-3 bg-gray-100 rounded w-4/6"></div>
                    </div>
                 </div>
             ))}
          </div>
      )}

      {/* Empty State */}
      {flatItems.length === 0 && status !== 'polling' && status !== 'initializing' && (
          <div className="text-center py-12 bg-white rounded-xl border border-dashed border-gray-300">
              <p className="text-gray-500">
                  {uniqueSymbols.length > 0 ? "No data matches your filters." : "No data loaded yet. Auto-fetching..."}
              </p>
          </div>
      )}

      {/* Grid vs List View */}
      <div className={`
        ${viewMode === 'grid' ? 'grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4' : 'flex flex-col gap-3'}
      `}>
          {paginatedItems.map(({ symbol, item }, idx) => {
              const cardKey = `${symbol}|${item.indicatorName}`;
              const isSelected = selectedCards.has(cardKey);
              // Fix logic: only show processing if it's NOT JSON yet AND still in ref list. 
              // Once it is JSON, we show it.
              const isProcessing = item.type !== 'json' && processingRef.current.has(`${symbol}-${item.indicatorName}`);

              return (
                  <BaseInsightCard
                    key={`${cardKey}-${idx}`}
                    symbol={symbol}
                    indicatorName={item.indicatorName}
                    url={item.url}
                    isProcessing={isProcessing}
                    success={item.success}
                    isSelected={isSelected}
                    onToggleSelect={() => toggleCardSelection(symbol, item.indicatorName)}
                    onStockClick={() => onSelectStock(symbol, getStockName(symbol))}
                  >
                     {renderSpecificCard(item.indicatorName, item.data)}
                  </BaseInsightCard>
              );
          })}
      </div>
    </div>
  );
};

export default BulkInsightManager;

import { useState, useRef, useEffect, useCallback } from 'react';
import { initiateBulkInsightExtraction, pollBulkInsightStatus, fetchStockSecInfo } from '../services/dataService';
import { processRawInsightData } from '../services/geminiService';
import { getTopElementInnerHTML } from '../services/helper';
import { InsightResultItem, PollStatusResponse } from '../types/trackingTypes';

const MAX_CONCURRENT_REQUESTS = 5;

export const useInsightExtraction = () => {
  const [results, setResults] = useState<Record<string, InsightResultItem[]>>({});
  const [status, setStatus] = useState<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>('idle');

  // Aggregate progress across all batches
  const [progress, setProgress] = useState({ completed: 0, total: 0 });

  // Track multiple active batches (Request IDs)
  const [activeRequestIds, setActiveRequestIds] = useState<Set<string>>(new Set());

  // Track progress of each individual batch to compute total
  const [batchProgress, setBatchProgress] = useState<Record<string, { completed: number; total: number }>>({});

  // Track ongoing Gemini processing to prevent duplicate calls
  const processingRef = useRef<Set<string>>(new Set());

  // --- Queue Management State ---
  const pendingBatchesRef = useRef<string[][]>([]);
  const initiatingCountRef = useRef(0);
  const invalidateCacheRef = useRef(false);

  // Signal to trigger queue processing checks
  const [queueTick, setQueueTick] = useState(0);

  const startExtraction = useCallback(async (symbols: string[], batchSize = 10, invalidateCache = false) => {
    if (symbols.length === 0) return;

    // Reset Batches Progress (New extraction cycle for these symbols)
    // Note: We don't clear 'results' to prevent UI flashing, but we reset tracking of current operation
    setBatchProgress({});
    setActiveRequestIds(new Set());

    // We only clear processing cache for the symbols we are about to fetch
    // But simplistic approach is to clear all for fresh fetching session
    // processingRef.current.clear(); 

    setStatus('initializing');
    setProgress({ completed: 0, total: symbols.length });

    // Setup Queue
    pendingBatchesRef.current = [];
    for (let i = 0; i < symbols.length; i += batchSize) {
      pendingBatchesRef.current.push(symbols.slice(i, i + batchSize));
    }
    invalidateCacheRef.current = invalidateCache;
    initiatingCountRef.current = 0;

    console.log(`[useInsightExtraction] Queued ${pendingBatchesRef.current.length} batches. Concurrency Limit: ${MAX_CONCURRENT_REQUESTS}`);

    // Trigger queue processing
    setQueueTick(prev => prev + 1);
  }, []);

  // --- Queue Processing Logic ---
  useEffect(() => {
    const processQueue = async () => {
        // Current Load = Active Polling Requests + Requests currently initiating (network flight)
        const currentLoad = activeRequestIds.size + initiatingCountRef.current;

        if (currentLoad >= MAX_CONCURRENT_REQUESTS) {
            // console.log(`[Queue] Max concurrency reached (${currentLoad}/${MAX_CONCURRENT_REQUESTS}). Waiting...`);
            return;
        }

        if (pendingBatchesRef.current.length === 0) return;

        // Calculate how many batches we can launch
        const slotsAvailable = MAX_CONCURRENT_REQUESTS - currentLoad;
        const batchesToLaunch = pendingBatchesRef.current.splice(0, slotsAvailable);

        if (batchesToLaunch.length > 0) {
            console.log(`[Queue] Launching ${batchesToLaunch.length} batches. Remaining in queue: ${pendingBatchesRef.current.length}`);

            batchesToLaunch.forEach(async (batch) => {
                initiatingCountRef.current += 1;
                try {
                    const response = await initiateBulkInsightExtraction(batch, invalidateCacheRef.current);
                    if (response && response.requestId) {
                        const rId = response.requestId;
                        console.log(`[Queue] Batch initiated. ID: ${rId}`);

                        // Register batch for polling
                        setBatchProgress(prev => ({
                            ...prev,
                            [rId]: { completed: 0, total: response.totalStocks }
                        }));
                        setActiveRequestIds(prev => new Set(prev).add(rId));
                        setStatus('polling');
                    } else {
                        console.error("Batch failed to initiate properly");
                    }
                } catch (e) {
                    console.error("Error initiating batch", e);
                } finally {
                    initiatingCountRef.current -= 1;
                    // Trigger check again as slot opened (or failed)
                    setQueueTick(prev => prev + 1);
                }
            });
        }
    };

    processQueue();
  }, [queueTick, activeRequestIds.size]); // Re-run when queueTick updates or active requests change (completion)


  // --- Polling Logic for Multiple Batches ---
  useEffect(() => {
    // Check for completion of all tasks
    if (activeRequestIds.size === 0 && pendingBatchesRef.current.length === 0 && initiatingCountRef.current === 0) {
      if (status === 'polling') {
          console.log("[useInsightExtraction] All batches completed.");
          setStatus('completed');
      }
      return;
    }

    if (activeRequestIds.size === 0) return;

    const pollAll = async () => {
      const ids = Array.from(activeRequestIds) as string[];

      await Promise.all(ids.map(async (id) => {
        const data = await pollBulkInsightStatus(id);

        if (data) {
          // 1. Update Results (Merge)
          setResults(prev => {
            const next = { ...prev };
            for (const [symbol, newItems] of Object.entries(data.results)) {
              const existingItems = next[symbol] || [];
              const mergedItems = [...existingItems];

              newItems.forEach(newItem => {
                const index = mergedItems.findIndex(i => i.indicatorName === newItem.indicatorName);
                if (index > -1) {
                  const existing = mergedItems[index];
                  // Preserve parsed JSON if new data is raw string (polling often returns same raw data)
                  if (existing.type === 'json' && typeof newItem.data === 'string') {
                    // Do nothing, keep existing parsed data
                  } else {
                    mergedItems[index] = newItem;
                  }
                } else {
                  mergedItems.push(newItem);
                }
              });
              next[symbol] = mergedItems;
            }
            return next;
          });

          // 2. Update Batch Progress
          setBatchProgress(prev => ({
            ...prev,
            [id]: { completed: data.completedStocks, total: data.totalStocks }
          }));

          // 3. Check for Completion of this batch
          if (data.status === 'resolved' || (data.totalStocks > 0 && data.completedStocks >= data.totalStocks)) {
            console.log(`[Polling] Batch ${id} completed.`);
            setActiveRequestIds(prev => {
              const next = new Set(prev);
              next.delete(id);
              return next;
            });
            // Slot opened, check queue
            setQueueTick(prev => prev + 1);
          }
        }
      }));
    };

    const intervalId = setInterval(pollAll, 5000);
    return () => clearInterval(intervalId);
  }, [activeRequestIds, status]);

  // --- Aggregate Progress ---
  useEffect(() => {
      if (Object.keys(batchProgress).length === 0) return;

      const totals = Object.values(batchProgress).reduce<{ completed: number; total: number }>((acc, curr) => ({
          completed: acc.completed + curr.completed,
          total: acc.total + curr.total
      }), { completed: 0, total: 0 });

      // Add pending items to total count to show real progress relative to initial request
      const pendingCount = pendingBatchesRef.current.reduce((acc, batch) => acc + batch.length, 0);
      const initiatingCount = initiatingCountRef.current * 10; // Approx

      // If we are just starting, ensure total reflects input
      if (totals.total > 0) {
          setProgress({
              completed: totals.completed,
              // Use the max of tracked total vs computed to avoid progress bar jumping back
              total: Math.max(totals.total + pendingCount, progress.total)
          });
      }
  }, [batchProgress, queueTick]); // queueTick dependency helps update when pending queue changes

  // --- Gemini Processing Logic ---
  useEffect(() => {
    Object.entries(results).forEach(([symbol, val]) => {
      const items = val as InsightResultItem[];
      items.forEach(async (item) => {
        const uniqueKey = `${symbol}-${item.indicatorName}`;

        if (item.geminiParsingReq && 
            item.success && 
            typeof item.data === 'string' && 
            item.data.trim().startsWith('<') &&
            !processingRef.current.has(uniqueKey)
        ) {
            processingRef.current.add(uniqueKey);

            try {
                let dataToParse = item.data;
                if(item.indicatorName === "Insider/SAST Deals") {
                  dataToParse = getTopElementInnerHTML(item.data);
                }

                const jsonStr = await processRawInsightData(dataToParse, item.geminiPrompt, item.indicatorName);

                let jsonObj;
                try {
                    jsonObj = JSON.parse(jsonStr);
                    // MERGE NSE DATA FOR PE CARD
                    if (item.indicatorName === 'PE') {
                         try {
                             const secInfo = await fetchStockSecInfo(symbol);
                             if (secInfo) {
                                 jsonObj.secInfo = secInfo;
                             }
                         } catch(e) {
                             console.warn(`Failed to fetch NSE SecInfo for ${symbol}`, e);
                         }
                    }
                } catch(e) {
                    jsonObj = { error: "Failed to parse data output", raw: jsonStr };
                }

                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: jsonObj,
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            } catch (err) {
                console.error("Processing failed for", uniqueKey);
                setResults(prev => {
                    const next = { ...prev };
                    const symItems = [...(next[symbol] || [])];
                    const itemIdx = symItems.findIndex(i => i.indicatorName === item.indicatorName);
                    if (itemIdx > -1) {
                        symItems[itemIdx] = {
                            ...symItems[itemIdx],
                            data: { error: "Processing failed" },
                            type: 'json'
                        };
                    }
                    next[symbol] = symItems;
                    return next;
                });
            }
        }
      });
    });
  }, [results]);

  return {
    results,
    setResults,
    status,
    setStatus,
    progress,
    setProgress,
    activeRequestIds,
    startExtraction
  };
};

import React, { useState, useEffect, useMemo } from 'react';
import { Loader2, RefreshCw, Filter, BrainCircuit, ChevronDown, ChevronLeft, ChevronRight, Search, EyeOff, Plus } from 'lucide-react';
import { fetchIndexConstituents } from '../../services/dataService';
import { processIndicatorData, ProcessedInsight } from '../../services/indicatorProcessor';
import { isTracked, addTrackedItem, removeTrackedItem, getTrackedIndices, getIgnoredItems, addIgnoredItem } from '../../services/trackingStorage';
import IntelligentStockCard from './cards/IntelligentStockCard';
import { InsightResultItem, IntelligentState } from '../../types/trackingTypes';

interface IntelligentTrackingManagerProps {
  onOpenChat: (context: any[]) => void;
  onSelectStock: (symbol: string, name: string) => void;
  // Props from parent hook
  extractionData: {
      results: Record<string, InsightResultItem[]>;
      status: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
      startExtraction: (symbols: string[], batchSize?: number, invalidateCache?: boolean) => Promise<void>;
      progress: { completed: number; total: number };
  };
  onStatsUpdate: (stats: { filtered: number; total: number; ignoredList: string[] }) => void;
  // Persisted View State
  viewState: IntelligentState;
  setViewState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const FILTER_TYPES = ["All", "Valuation", "Technicals", "Holdings", "Performance", "Deals"];
const BATCH_SIZE = 10;

const IntelligentTrackingManager: React.FC<IntelligentTrackingManagerProps> = ({ 
  onOpenChat, 
  onSelectStock,
  extractionData,
  onStatsUpdate,
  viewState,
  setViewState
}) => {
  const [loadingSymbols, setLoadingSymbols] = useState(false);
  const [trackTick, setTrackTick] = useState(0);
  const [availableIndices, setAvailableIndices] = useState<string[]>([]);
  const [searchQuery, setSearchQuery] = useState('');

  // Selection and Force Refresh State
  const [selectedSymbols, setSelectedSymbols] = useState<Set<string>>(new Set());
  const [forceRefresh, setForceRefresh] = useState(false);

  // Ignore list state to filter locally
  const [ignoredItems, setIgnoredItems] = useState<string[]>([]);

  // Current Index Ignored List
  const [currentIndexIgnored, setCurrentIndexIgnored] = useState<string[]>([]);

  // Destructure hook data
  const { results, status, startExtraction, progress } = extractionData;

  // Local state for processed trigger data (Derived from results, so safe to be local)
  const [processedStocks, setProcessedStocks] = useState<Record<string, ProcessedInsight[]>>({});
  const [processingData, setProcessingData] = useState(false);

  // Helper to update specific view state fields
  const updateState = (updates: Partial<IntelligentState>) => {
      setViewState(prev => ({ ...prev, ...updates }));
  };

  // 0. Load Available Indices & Ignored List
  useEffect(() => {
    const loadData = () => {
        const indices = getTrackedIndices();
        setAvailableIndices(indices);
        setIgnoredItems(getIgnoredItems());

        // Safety check: if current selected index was deleted, default to first available
        if (indices.length > 0 && !indices.includes(viewState.selectedIndex)) {
            updateState({ selectedIndex: indices[0], symbols: [], page: 1 });
        }
    };
    loadData();

    // Listen for storage changes
    const handleUpdate = () => loadData();
    window.addEventListener('fundflow_tracking_update', handleUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleUpdate);
  }, [viewState.selectedIndex]);

  // 1. Fetch Index Symbols on Change (Persisted in viewState.symbols)
  useEffect(() => {
     // If we already have symbols for this index, we still need to re-calculate ignored items 
     // because ignore list might have changed.

     // Only fetch if we have a valid selected index
     if (!viewState.selectedIndex) return;

     const loadSymbols = async () => {
         // Avoid re-fetching API if we just want to re-filter
         const alreadyLoaded = viewState.symbols.length > 0 && !loadingSymbols;

         if(!alreadyLoaded) setLoadingSymbols(true);

         try {
             // For simplicity, we always refetch constituents to ensure we get the full list for calculating ignored
             // Optimization: We could cache raw index response
             const allSymbols = await fetchIndexConstituents(viewState.selectedIndex);

             const ignored = getIgnoredItems();
             const ignoredInIndex = allSymbols.filter(s => ignored.includes(s));
             const cleanSymbols = allSymbols.filter(s => !ignored.includes(s));

             setCurrentIndexIgnored(ignoredInIndex);

             // Only update viewState if it actually changed (shallow check optimization implied)
             if (!alreadyLoaded || cleanSymbols.length !== viewState.symbols.length) {
                 updateState({ symbols: cleanSymbols, page: 1 }); 
                 setSelectedSymbols(new Set());
             }
         } catch (e) {
             console.error("Failed to fetch index symbols", e);
             updateState({ symbols: [] });
         } finally {
             setLoadingSymbols(false);
         }
     };
     loadSymbols();
  }, [viewState.selectedIndex, trackTick]); // re-run if tracking/ignore list changes (trackTick updates on ignore action)

  // 2. Start Extraction logic (Smart Refresh for Missing Symbols)
  useEffect(() => {
      const isFetching = status === 'initializing' || status === 'polling';
      if (viewState.symbols.length === 0 || isFetching) return;

      // Identify which symbols in the current view don't have results yet
      const missingSymbols = viewState.symbols.filter(sym => !results[sym] || results[sym].length === 0);

      if (missingSymbols.length > 0) {
          // Fetch only the missing ones (no force refresh for auto-fetch)
          startExtraction(missingSymbols, BATCH_SIZE, false);
      }
  }, [viewState.symbols, status, results, startExtraction]);

  // 3. Process Raw Results into Intelligent Insights
  useEffect(() => {
      const processResults = async () => {
          if (Object.keys(results).length === 0) {
              setProcessedStocks({});
              return;
          }

          setProcessingData(true);
          const newProcessed: Record<string, ProcessedInsight[]> = {};

          for (const [symbol, val] of Object.entries(results)) {
              const items = val as InsightResultItem[];
              // Optimization: Only process symbols relevant to current index to save performance
              if (!viewState.symbols.includes(symbol)) continue;

              const stockInsights: ProcessedInsight[] = [];
              for (const item of items) {
                  if (item.success && (item.type === 'json' || item.data)) {
                       const insight = await processIndicatorData(symbol, item.indicatorName, item.data);
                       if (insight.status === 'triggered') {
                           stockInsights.push(insight);
                       }
                  }
              }
              if (stockInsights.length > 0) {
                  newProcessed[symbol] = stockInsights;
              }
          }
          setProcessedStocks(newProcessed);
          setProcessingData(false);
      };

      const timer = setTimeout(processResults, 1000);
      return () => clearTimeout(timer);
  }, [results, viewState.symbols]);

  // 4. Filter Logic
  const filteredStocks = useMemo(() => {
      return (Object.entries(processedStocks) as [string, ProcessedInsight[]][]).filter(([symbol, insights]) => {
          // 0. Double check ignore list
          if (ignoredItems.includes(symbol)) return false;

          // 1. Filter by Insight Type
          const matchesType = viewState.filter === "All" || insights.some(i => i.type === viewState.filter);
          if (!matchesType) return false;

          // 2. Filter by Search Query
          if (!searchQuery) return true;
          const lowerQ = searchQuery.toLowerCase();

          if (symbol.toLowerCase().includes(lowerQ)) return true;
          if (insights.some(i => i.text?.toLowerCase().includes(lowerQ))) return true;

          return false;
      }).sort((a, b) => b[1].length - a[1].length); 
  }, [processedStocks, viewState.filter, searchQuery, ignoredItems]);

  // 5. Pagination Logic
  const paginatedStocks = useMemo(() => {
      const startIndex = (viewState.page - 1) * viewState.pageSize;
      return filteredStocks.slice(startIndex, startIndex + viewState.pageSize);
  }, [filteredStocks, viewState.page, viewState.pageSize]);

  const totalPages = Math.ceil(filteredStocks.length / viewState.pageSize);

  // 6. Update Parent Stats
  useEffect(() => {
      onStatsUpdate({
          filtered: filteredStocks.length,
          total: viewState.symbols.length,
          ignoredList: currentIndexIgnored
      });
  }, [filteredStocks.length, viewState.symbols.length, currentIndexIgnored, onStatsUpdate]);

  const handleToggleSelect = (symbol: string) => {
      const newSet = new Set(selectedSymbols);
      if (newSet.has(symbol)) {
          newSet.delete(symbol);
      } else {
          newSet.add(symbol);
      }
      setSelectedSymbols(newSet);
  };

  const handleManualRefresh = () => {
      if (selectedSymbols.size > 0) {
          startExtraction(Array.from(selectedSymbols), BATCH_SIZE, true);
          setSelectedSymbols(new Set()); 
      } else if (viewState.symbols.length > 0) {
          startExtraction(viewState.symbols, BATCH_SIZE, forceRefresh);
      }
  };

  const handleIgnoreSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toIgnore = Array.from(selectedSymbols);
      toIgnore.forEach(sym => addIgnoredItem(sym));

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleTrackSelected = () => {
      if (selectedSymbols.size === 0) return;

      const toTrack = Array.from(selectedSymbols);
      toTrack.forEach(sym => {
          // Use symbol as name if full name isn't readily available in this context
          addTrackedItem({ id: sym, name: sym, symbol: sym, type: 'STOCK' });
      });

      setTrackTick(prev => prev + 1);
      setSelectedSymbols(new Set());
  };

  const handleCardRefresh = (symbol: string) => {
      startExtraction([symbol], 1, true);
  };

  return (
    <div className="space-y-6">
       {/* Controls Bar */}
       <div className="bg-white rounded-xl border border-gray-200 p-4 flex flex-col xl:flex-row items-center justify-between gap-4 shadow-sm">

           <div className="flex flex-col md:flex-row items-center gap-4 w-full xl:w-auto">
               {/* Index Selector */}
               <div className="relative w-full md:w-48">
                   <select 
                       value={viewState.selectedIndex as string}
                       onChange={(e) => {
                           updateState({ selectedIndex: e.target.value, symbols: [], page: 1 }); 
                       }}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-4 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                       disabled={loadingSymbols || status === 'initializing'}
                   >
                       {availableIndices.map(idx => <option key={idx} value={idx}>{idx}</option>)}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Search Box */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Search size={16} className="text-gray-400" />
                   </div>
                   <input 
                       type="text"
                       value={searchQuery as string}
                       onChange={(e) => setSearchQuery(e.target.value)}
                       placeholder="Search insights..."
                       className="w-full bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-3 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                   />
               </div>

               <div className="h-6 w-px bg-gray-200 hidden md:block"></div>

               {/* Filter Dropdown */}
               <div className="relative w-full md:w-48">
                   <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                        <Filter size={16} className="text-gray-400" />
                   </div>
                   <select 
                       value={viewState.filter}
                       onChange={(e) => updateState({ filter: e.target.value, page: 1 })}
                       className="w-full appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm font-medium rounded-lg pl-9 pr-10 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 cursor-pointer"
                   >
                       {FILTER_TYPES.map(type => (
                           <option key={type} value={type}>{type} Insights</option>
                       ))}
                   </select>
                   <ChevronDown size={16} className="absolute right-3 top-1/2 transform -translate-y-1/2 text-gray-400 pointer-events-none" />
               </div>

                {/* Force Refresh Checkbox (Only visible if no selection, as selection implies force) */}
               {selectedSymbols.size === 0 && (
                   <label className="flex items-center gap-2 text-sm text-gray-600 cursor-pointer whitespace-nowrap ml-2">
                       <input 
                           type="checkbox" 
                           checked={forceRefresh} 
                           onChange={(e) => setForceRefresh(e.target.checked)}
                           className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                       />
                       Invalidate Cache
                   </label>
               )}
           </div>

           {/* Right Side: Pagination & Status */}
           <div className="flex items-center gap-4 w-full xl:w-auto justify-between xl:justify-end">

               {filteredStocks.length > 0 && (
                   <div className="flex items-center gap-3">
                       <div className="flex items-center gap-2">
                           <span className="text-xs text-gray-500">Rows:</span>
                           <select 
                             value={viewState.pageSize} 
                             onChange={(e) => updateState({ pageSize: Number(e.target.value), page: 1 })}
                             className="bg-gray-50 border border-gray-200 text-gray-700 text-xs rounded-lg p-1.5"
                           >
                               <option value={10}>10</option>
                               <option value={20}>20</option>
                               <option value={50}>50</option>
                               <option value={100}>100</option>
                           </select>
                       </div>

                       <div className="flex items-center gap-1">
                            <button
                                onClick={() => updateState({ page: Math.max(1, viewState.page - 1) })}
                                disabled={viewState.page === 1}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronLeft size={16} />
                            </button>
                            <span className="text-xs font-medium w-16 text-center">
                                {viewState.page} / {totalPages}
                            </span>
                            <button
                                onClick={() => updateState({ page: Math.min(totalPages, viewState.page + 1) })}
                                disabled={viewState.page === totalPages}
                                className="p-1.5 rounded-md border border-gray-200 hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed"
                            >
                                <ChevronRight size={16} />
                            </button>
                       </div>
                   </div>
               )}

               <div className="h-6 w-px bg-gray-200 hidden xl:block"></div>

               {loadingSymbols ? (
                   <span className="text-xs text-gray-500 flex items-center gap-2">
                       <Loader2 size={14} className="animate-spin" /> Fetching Symbols...
                   </span>
               ) : status === 'initializing' || status === 'polling' ? (
                   <div className="flex items-center gap-3">
                       <span className="text-xs text-gray-500 flex items-center gap-2">
                           <Loader2 size={14} className="animate-spin text-indigo-600" /> 
                           Analyzing {progress.completed}/{progress.total}
                       </span>
                   </div>
               ) : selectedSymbols.size > 0 ? (
                   <div className="flex items-center gap-2">
                       <button 
                           onClick={handleTrackSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-green-50 text-green-600 hover:bg-green-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Watchlist"
                       >
                           <Plus size={16} />
                           Track ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleIgnoreSelected}
                           className="flex items-center gap-2 px-3 py-2 bg-red-50 text-red-600 hover:bg-red-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Add selected to Ignore List (Do not track)"
                       >
                           <EyeOff size={16} />
                           Ignore ({selectedSymbols.size})
                       </button>
                       <button 
                           onClick={handleManualRefresh}
                           className="flex items-center gap-2 px-3 py-2 bg-indigo-50 text-indigo-600 hover:bg-indigo-100 rounded-lg transition-colors text-sm font-medium whitespace-nowrap"
                           title="Force Refresh Selected"
                       >
                           <RefreshCw size={16} />
                           Refresh
                       </button>
                   </div>
               ) : (
                   <button 
                       onClick={handleManualRefresh}
                       className="p-2 text-gray-600 hover:text-indigo-600 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-200"
                       title="Refresh List"
                   >
                       <RefreshCw size={20} />
                   </button>
               )}
           </div>
       </div>

       {/* Content Grid */}
       {loadingSymbols ? (
           <div className="flex flex-col items-center justify-center py-20 text-gray-400">
               <Loader2 size={32} className="animate-spin text-indigo-500 mb-2" />
               <p className="text-sm">Loading Index Constituents...</p>
           </div>
       ) : paginatedStocks.length > 0 ? (
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
               {paginatedStocks.map(([symbol, insights]) => (
                   <IntelligentStockCard 
                       key={symbol}
                       symbol={symbol}
                       insights={insights}
                       isTracked={isTracked(symbol, 'STOCK')}
                       onOpenDeepDive={() => onSelectStock(symbol, symbol)}
                       onAskAI={() => onOpenChat(insights.map(i => ({ symbol, type: i.type, insight: i.text, rawData: i.data })))}
                       onRefresh={() => handleCardRefresh(symbol)}
                       isSelected={selectedSymbols.has(symbol)}
                       onToggleSelect={() => handleToggleSelect(symbol)}
                   />
               ))}
           </div>
       ) : (
           <div className="flex flex-col items-center justify-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
               {status === 'initializing' || status === 'polling' || processingData ? (
                   <>
                      <BrainCircuit size={48} className="text-indigo-200 mb-4 animate-pulse" />
                      <h3 className="text-lg font-medium text-gray-900">Analysis in Progress</h3>
                      <p className="text-gray-500 mt-1">Processing data in batches of {BATCH_SIZE}...</p>
                   </>
               ) : (
                   <>
                      <p className="text-gray-500">No stocks found matching your criteria.</p>
                      <p className="text-xs text-gray-400 mt-1">Try changing the filter, search query, or refreshing analysis.</p>
                   </>
               )}
           </div>
       )}
    </div>
  );
};

export default IntelligentTrackingManager;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { Search, Loader2, RefreshCw, Database, Sparkles, ExternalLink, BarChart2, BrainCircuit, X, Globe, TrendingUp, TrendingDown } from 'lucide-react';
import InsightCard from './InsightCard';
import BulkInsightManager from './BulkInsightManager';
import IntelligentTrackingManager from './IntelligentTrackingManager';
import InsightChatbot from './InsightChatbot';
import MarketOverview from './MarketOverview';
import { getTrackedItems, TrackedItem, getTrackedIndices } from '../../services/trackingStorage';
import { fetchMarketInsights } from '../../services/geminiService';
import { fetchMarketIndices } from '../../services/dataService';
import { Insight, InsightResultItem, IntelligentState, MarketIndexData } from '../../types/trackingTypes';
import { FundSearchResult } from '../../types';
import { HEADER_INDICES } from '../../types/constants';
import { useInsightExtraction } from '../../hooks/useInsightExtraction';

interface TrackingDashboardProps {
  onSelectStock: (symbol: string, name: string) => void;
  onSelectFund: (fund: FundSearchResult) => void;
  // Deep Dive State
  bulkResults: Record<string, InsightResultItem[]>;
  setBulkResults: React.Dispatch<React.SetStateAction<Record<string, InsightResultItem[]>>>;
  bulkStatus: 'idle' | 'initializing' | 'polling' | 'completed' | 'error';
  setBulkStatus: React.Dispatch<React.SetStateAction<'idle' | 'initializing' | 'polling' | 'completed' | 'error'>>;
  bulkProgress: { completed: number; total: number };
  setBulkProgress: React.Dispatch<React.SetStateAction<{ completed: number; total: number }>>;
  requestId: string | null;
  setRequestId: React.Dispatch<React.SetStateAction<string | null>>;
  // Intelligent State
  intelligentExtraction: ReturnType<typeof useInsightExtraction>;
  intelligentState: IntelligentState;
  setIntelligentState: React.Dispatch<React.SetStateAction<IntelligentState>>;
}

const TrackingDashboard: React.FC<TrackingDashboardProps> = ({ 
  onSelectStock, 
  onSelectFund,
  bulkResults,
  setBulkResults,
  bulkStatus,
  setBulkStatus,
  bulkProgress,
  setBulkProgress,
  requestId,
  setRequestId,
  intelligentExtraction,
  intelligentState,
  setIntelligentState
}) => {
  const [activeStreamTab, setActiveStreamTab] = useState<'DEEP_DIVE' | 'AI' | 'INTELLIGENT' | 'MARKET'>('MARKET');

  // Global Data State
  const [entities, setEntities] = useState<TrackedItem[]>([]);

  // Market Index Data (Shared across tabs for header)
  const [marketIndices, setMarketIndices] = useState<MarketIndexData[]>([]);
  const [loadingIndices, setLoadingIndices] = useState(false);

  // Market News State
  const [insights, setInsights] = useState<Insight[]>([]);
  const [loadingInsights, setLoadingInsights] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');

  // Chat State
  const [chatContext, setChatContext] = useState<any[] | null>(null);

  // Local stats for display
  const [intelligentStats, setIntelligentStats] = useState<{ filtered: number; total: number; ignoredList: string[] }>({ filtered: 0, total: 0, ignoredList: [] });
  const [showIgnoredPopover, setShowIgnoredPopover] = useState(false);
  const ignoredPopoverRef = useRef<HTMLDivElement>(null);

  // Load initial data and listen for updates
  useEffect(() => {
    const loadItems = () => {
        const loadedEntities = getTrackedItems();
        setEntities(loadedEntities);
    };

    loadItems();

    const handleStorageUpdate = () => {
        loadItems();
    };

    window.addEventListener('fundflow_tracking_update', handleStorageUpdate);
    return () => window.removeEventListener('fundflow_tracking_update', handleStorageUpdate);
  }, []); 

  // Fetch Market Indices on Mount
  useEffect(() => {
      const loadIndices = async () => {
          setLoadingIndices(true);
          const data = await fetchMarketIndices();
          setMarketIndices(data);
          setLoadingIndices(false);
      };
      loadIndices();
  }, []);

  // Close popover on click outside
  useEffect(() => {
      const handleClickOutside = (event: MouseEvent) => {
          if (ignoredPopoverRef.current && !ignoredPopoverRef.current.contains(event.target as Node)) {
              setShowIgnoredPopover(false);
          }
      };
      document.addEventListener('mousedown', handleClickOutside);
      return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const fetchInsights = async () => {
     if (entities.length === 0) return;
     setLoadingInsights(true);
     try {
         const data = await fetchMarketInsights(entities);
         setInsights(data);
     } catch (err) {
         console.error(err);
     } finally {
         setLoadingInsights(false);
     }
  };

  const filteredInsights = useMemo(() => {
    let filtered = insights;
    if (searchQuery) {
        const lowerQ = searchQuery.toLowerCase();
        filtered = filtered.filter(i => 
        i.title.toLowerCase().includes(lowerQ) || 
        i.content.toLowerCase().includes(lowerQ)
        );
    }
    return filtered.map(item => {
        const entity = entities.find(e => e.id === item.entityId);
        return { ...item, entityName: entity?.name || 'Unknown', entitySymbol: entity?.symbol };
    }).sort((a,b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [insights, entities, searchQuery]);

  // Header Indices Data
  const headerIndicesData = useMemo(() => {
      return marketIndices.filter(idx => HEADER_INDICES.includes(idx.index));
  }, [marketIndices]);

  return (
    <div className="flex flex-col gap-6 animate-fade-in w-full max-w-7xl mx-auto relative">

      {/* Header & Tabs */}
      <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
         <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 mb-6">
            <div>
              <h2 className="text-2xl font-bold text-gray-900">Market Intelligence</h2>
              <p className="text-gray-500 text-sm relative mt-1">
                {activeStreamTab === 'INTELLIGENT' 
                  ? (
                    <span>
                      Showing <strong>{intelligentStats.filtered}</strong> potential stocks from index ({intelligentStats.total} active)
                      {intelligentStats.ignoredList.length > 0 && (
                          <span className="ml-1 text-red-400">
                              • <span 
                                  className="cursor-pointer underline decoration-dotted hover:text-red-600"
                                  onClick={() => setShowIgnoredPopover(!showIgnoredPopover)}
                                >
                                  {intelligentStats.ignoredList.length} ignored
                                </span>
                          </span>
                      )}
                    </span>
                  )
                  : activeStreamTab === 'MARKET' ? "Overview of global and tracked indices"
                  : `Tracking ${entities.length} items in your portfolio`
                }
              </p>

              {/* Ignored List Popover */}
              {showIgnoredPopover && intelligentStats.ignoredList.length > 0 && (
                  <div 
                    ref={ignoredPopoverRef}
                    className="absolute z-50 mt-2 bg-white border border-gray-200 rounded-lg shadow-xl p-3 w-64 animate-fade-in left-0 md:left-auto"
                  >
                      <div className="flex justify-between items-center mb-2 pb-2 border-b border-gray-100">
                          <h4 className="text-xs font-bold text-gray-700">Ignored in this Index</h4>
                          <button onClick={() => setShowIgnoredPopover(false)} className="text-gray-400 hover:text-gray-600">
                              <X size={14} />
                          </button>
                      </div>
                      <div className="max-h-48 overflow-y-auto space-y-1">
                          {intelligentStats.ignoredList.map(sym => (
                              <div 
                                key={sym} 
                                className="text-xs text-gray-600 px-2 py-1 rounded hover:bg-gray-50 cursor-pointer flex justify-between"
                                onClick={() => { onSelectStock(sym, sym); setShowIgnoredPopover(false); }}
                              >
                                  <span>{sym}</span>
                                  <ExternalLink size={10} className="text-gray-400 opacity-50" />
                              </div>
                          ))}
                      </div>
                  </div>
              )}
            </div>

            {/* Subtle Market Header Stats - Compact & Corner */}
            {headerIndicesData.length > 0 && (
                <div className="flex flex-wrap gap-2 justify-end">
                    {headerIndicesData.map(idx => {
                        const isPos = idx.percentChange >= 0;
                        const tooltipText = `PE: ${idx.pe}\nPrevious Close: ${idx.previousClose}\nOpen: ${idx.open}\nHigh: ${idx.high}\nLow: ${idx.low}\nYear High: ${idx.yearHigh}\nYear Low: ${idx.yearLow}`;

                        return (
                            <div 
                                key={idx.index} 
                                className="flex items-center gap-1.5 bg-gray-50 px-2.5 py-1.5 rounded-lg border border-gray-100 text-xs cursor-help hover:bg-gray-100 hover:border-gray-300 transition-colors"
                                title={tooltipText}
                            >
                                <span className="font-semibold text-gray-700">{idx.index}</span>
                                <span className="font-mono text-gray-800">{idx.last.toLocaleString()}</span>
                                <span className={`font-medium ml-0.5 ${isPos ? 'text-green-600' : 'text-red-600'}`}>
                                    {isPos ? '+' : ''}{idx.percentChange.toFixed(2)}%
                                </span>
                            </div>
                        );
                    })}
                </div>
            )}
         </div>

         {/* Tab Navigation - Updated Order */}
         <div className="flex items-center gap-6 border-b border-gray-200 overflow-x-auto">
             <button
                onClick={() => setActiveStreamTab('MARKET')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'MARKET' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Globe size={18} />
                Market Overview
             </button>
             <button
                onClick={() => setActiveStreamTab('INTELLIGENT')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'INTELLIGENT' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <BrainCircuit size={18} />
                Intelligent Tracking
             </button>
             <button
                onClick={() => setActiveStreamTab('DEEP_DIVE')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'DEEP_DIVE' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <BarChart2 size={18} />
                Tracked Assets
             </button>
             <button
                onClick={() => setActiveStreamTab('AI')}
                className={`flex items-center gap-2 px-2 py-3 text-sm font-medium border-b-2 transition-colors whitespace-nowrap ${
                    activeStreamTab === 'AI' 
                    ? 'border-indigo-600 text-indigo-600' 
                    : 'border-transparent text-gray-500 hover:text-gray-700'
                }`}
             >
                <Sparkles size={18} />
                Market News
             </button>
         </div>
      </div>

      {/* Main Content Area */}
      <div className="min-h-[500px]">

         {/* MARKET OVERVIEW */}
         {activeStreamTab === 'MARKET' && (
             <MarketOverview indicesData={marketIndices} />
         )}

         {/* INTELLIGENT TRACKING VIEW */}
         {activeStreamTab === 'INTELLIGENT' && (
            <IntelligentTrackingManager 
                onOpenChat={(ctx) => setChatContext(ctx)}
                onSelectStock={onSelectStock}
                extractionData={intelligentExtraction}
                onStatsUpdate={setIntelligentStats}
                // Pass persisted state props
                viewState={intelligentState}
                setViewState={setIntelligentState}
            />
         )}

         {/* TRACKED ASSETS (Deep Dive) VIEW */}
         {activeStreamTab === 'DEEP_DIVE' && (
            <BulkInsightManager 
                items={entities}
                results={bulkResults}
                setResults={setBulkResults}
                status={bulkStatus}
                setStatus={setBulkStatus}
                progress={bulkProgress}
                setProgress={setBulkProgress}
                requestId={requestId}
                setRequestId={setRequestId}
                onOpenChat={(ctx) => setChatContext(ctx)}
                onSelectStock={onSelectStock}
            />
         )}

         {/* MARKET NEWS VIEW */}
         {activeStreamTab === 'AI' && (
            <div className="space-y-4">
               <div className="flex items-center justify-between pb-2">
                  <p className="text-xs text-gray-500">
                      {loadingInsights 
                        ? 'Analyzing market data...' 
                        : `${filteredInsights.length} insights generated via Gemini`
                      }
                  </p>
                  <button 
                      onClick={fetchInsights} 
                      disabled={loadingInsights}
                      className="flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-lg hover:bg-indigo-100 transition-colors text-sm font-medium"
                  >
                      {loadingInsights ? <Loader2 size={16} className="animate-spin"/> : <RefreshCw size={16} />}
                      Generate New Insights
                  </button>
               </div>

               {loadingInsights && filteredInsights.length === 0 ? (
                  <div className="p-12 flex flex-col items-center justify-center space-y-3 bg-white rounded-xl border border-gray-100">
                      <Loader2 size={32} className="animate-spin text-indigo-600" />
                      <p className="text-gray-500 text-sm">Gathering intelligent insights...</p>
                  </div>
               ) : filteredInsights.length > 0 ? (
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                      {filteredInsights.map(insight => (
                          <InsightCard key={insight.id} insight={insight} />
                      ))}
                  </div>
               ) : (
                  <div className="text-center py-16 bg-white rounded-xl border border-dashed border-gray-300">
                      <Sparkles size={48} className="mx-auto text-indigo-200 mb-4" />
                      <h3 className="text-lg font-medium text-gray-900">AI Market News</h3>
                      <p className="text-gray-500 max-w-sm mx-auto mt-2">
                          Get real-time summaries and sentiment analysis for your portfolio items powered by Gemini 2.5.
                      </p>
                      <button 
                          onClick={fetchInsights}
                          className="mt-6 px-6 py-2 bg-indigo-600 text-white rounded-full font-medium hover:bg-indigo-700 transition-shadow shadow-md"
                      >
                          Generate News
                      </button>
                  </div>
               )}
            </div>
         )}
      </div>

      {/* Floating Chatbot Overlay */}
      {chatContext && (
          <InsightChatbot 
              contextData={chatContext} 
              onClose={() => setChatContext(null)} 
          />
      )}
    </div>
  );
};

export default TrackingDashboard;

import React from 'react';
import { MarketIndexData } from '../../types/trackingTypes';
import { MARKET_OVERVIEW_INDICES } from '../../types/constants';
import { getTrackedIndices } from '../../services/trackingStorage';
import { Activity, BarChart2, TrendingUp, TrendingDown, Minus } from 'lucide-react';

interface MarketOverviewProps {
  indicesData: MarketIndexData[];
}

const IndexRow: React.FC<{ data: MarketIndexData, isAlternate?: boolean }> = ({ data, isAlternate }) => {
  const isPositive = data.percentChange >= 0;
  const colorClass = isPositive ? 'text-green-600' : 'text-red-600';

  // Calculate 1W return
  const oneWeekReturn = data.oneWeekAgoVal 
    ? ((data.last - data.oneWeekAgoVal) / data.oneWeekAgoVal * 100).toFixed(2) 
    : '-';

  // Breadth
  const advances = parseInt(data.advances || "0", 10);
  const declines = parseInt(data.declines || "0", 10);
  const total = advances + declines;
  const advanceWidth = total > 0 ? (advances / total) * 100 : 50;

  // 52 Week Range
  const rangePos = data.yearHigh && data.yearLow
    ? ((data.last - data.yearLow) / (data.yearHigh - data.yearLow)) * 100
    : 0;

  return (
    <tr className={`hover:bg-indigo-50/50 transition-colors border-b border-gray-50 ${isAlternate ? 'bg-gray-50/30' : ''}`}>
        <td className="px-4 py-3 font-semibold text-gray-800">{data.index}</td>
        <td className="px-4 py-3 text-right font-mono text-gray-700">{data.last.toLocaleString()}</td>
        <td className={`px-4 py-3 text-right font-medium ${colorClass}`}>
            {isPositive ? '+' : ''}{data.percentChange.toFixed(2)}%
        </td>

        {/* Valuation (PE | PB | DY) */}
        <td className="px-4 py-3 text-center text-gray-600">
            <div className="flex items-center justify-center gap-2 text-[11px]">
                <span className="font-medium bg-gray-100 px-1.5 py-0.5 rounded text-gray-700" title="P/E">{data.pe || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="P/B">{data.pb || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="Yield">{data.dy || '-'}</span>
            </div>
        </td>

        {/* Returns */}
        <td className="px-4 py-3 text-center">
