import React, { useState, useRef, useEffect } from 'react';
import { Lightbulb, Loader2, X, TrendingUp, TrendingDown, Minus, ExternalLink } from 'lucide-react';
import { fetchIndexInsights } from '../../services/dataService';
import { IndexInsightCategory } from '../../types/trackingTypes';
import { getTrackedItems } from '../../services/trackingStorage';

interface IndexInsightsWidgetProps {
  indexName: string;
  onSelectStock: (symbol: string, name: string) => void;
  preloadedData?: IndexInsightCategory[];
  isLoading?: boolean;
}

const IndexInsightsWidget: React.FC<IndexInsightsWidgetProps> = ({ 
    indexName, 
    onSelectStock, 
    preloadedData, 
    isLoading: parentLoading 
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [localLoading, setLocalLoading] = useState(false);
  const [localData, setLocalData] = useState<IndexInsightCategory[]>([]);
  const popoverRef = useRef<HTMLDivElement>(null);

  // Use preloaded data if available, otherwise local state
  const data = preloadedData || localData;
  const loading = parentLoading !== undefined ? parentLoading : localLoading;

  // Close on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    if (isOpen) document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const handleToggle = async (e: React.MouseEvent) => {
      e.stopPropagation();

      // If controlled by parent (preloadedData provided), just toggle
      if (preloadedData !== undefined) {
          if (data.length > 0) setIsOpen(!isOpen);
          return;
      }

      // Legacy/Self-managed mode (fetch on click)
      if (!isOpen && data.length === 0) {
          setLocalLoading(true);
          setIsOpen(true);

          try {
              const insights = await fetchIndexInsights(indexName);
              const trackedItems = getTrackedItems();
              const trackedSymbols = new Set(trackedItems.filter(i => i.type === 'STOCK').map(i => i.id));

              const filteredInsights = insights.map(category => ({
                  ...category,
                  items: category.items.filter(item => trackedSymbols.has(item.symbol))
              })).filter(category => category.items.length > 0);

              setLocalData(filteredInsights);
          } catch (error) {
              console.error("Failed to fetch insights", error);
          } finally {
              setLocalLoading(false);
          }
      } else {
          setIsOpen(!isOpen);
      }
  };

  const totalInsights = data.reduce((acc, cat) => acc + cat.items.length, 0);

  const getIcon = (type: string) => {
      if (type === 'positive') return <TrendingUp size={12} className="text-green-600" />;
      if (type === 'negative') return <TrendingDown size={12} className="text-red-600" />;
      return <Minus size={12} className="text-gray-400" />;
  };

  // If no data and not loading (and using preloaded mode), don't show anything or show empty state? 
  // Requirement says "Display that count... if anything is found display that count".
  // So if 0, we might want to show nothing or a grayed out icon.
  // Let's show a subtle indicator if 0 but loading, or nothing if 0 and loaded.

  if (!loading && totalInsights === 0 && preloadedData !== undefined) {
      return null;
  }

  return (
    <div className="relative inline-block ml-2" ref={popoverRef}>
        <button 
            onClick={handleToggle}
            disabled={loading && totalInsights === 0}
            className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold transition-all shadow-sm ${
                isOpen 
                ? 'bg-indigo-600 text-white' 
                : totalInsights > 0 
                    ? 'bg-indigo-100 text-indigo-700 hover:bg-indigo-200 border border-indigo-200'
                    : 'bg-gray-50 text-gray-400 border border-gray-100'
            }`}
            title="Insights for Tracked Stocks"
        >
            {loading && totalInsights === 0 ? (
                <Loader2 size={10} className="animate-spin" />
            ) : (
                <Lightbulb size={10} className={totalInsights > 0 ? "fill-indigo-700" : ""} />
            )}

            {loading && totalInsights === 0 ? '' : totalInsights}
        </button>

        {isOpen && (
            <div className="absolute z-50 mt-2 w-72 bg-white border border-gray-200 shadow-xl rounded-xl overflow-hidden left-0 top-full animate-fade-in origin-top-left">
                <div className="bg-gray-50 px-4 py-2 border-b border-gray-100 flex items-center justify-between">
                    <h4 className="font-bold text-gray-800 text-xs">Insights for {indexName}</h4>
                    <button 
                        onClick={() => setIsOpen(false)}
                        className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-200 transition-colors"
                    >
                        <X size={12} />
                    </button>
                </div>

                <div className="max-h-64 overflow-y-auto custom-scrollbar p-1">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-4 text-gray-400 gap-1">
                            <Loader2 size={16} className="animate-spin text-indigo-500" />
                            <span className="text-[10px]">Updating...</span>
                        </div>
                    ) : totalInsights === 0 ? (
                        <div className="p-3 text-center text-[10px] text-gray-400 italic">
                            No active insights for your tracked stocks in this index.
                        </div>
                    ) : (
                        <div className="space-y-2 p-1">
                            {data.map(category => (
                                category.items.length > 0 && (
                                    <div key={category.id}>
                                        <h5 className="text-[9px] font-bold text-gray-400 uppercase tracking-wider mb-1 ml-1 border-b border-gray-50 pb-0.5">
                                            {category.title}
                                        </h5>
                                        <div className="space-y-1">
                                            {category.items.map((item, idx) => (
                                                <div 
                                                    key={`${category.id}-${idx}`}
                                                    onClick={() => {
                                                        onSelectStock(item.symbol, item.symbol);
                                                        setIsOpen(false);
                                                    }}
                                                    className="group flex gap-2 p-2 rounded hover:bg-indigo-50 border border-transparent hover:border-indigo-100 cursor-pointer transition-all items-start"
                                                >
                                                    <div className={`mt-0.5 shrink-0 bg-white p-0.5 rounded border border-gray-100 shadow-sm`}>
                                                        {getIcon(item.type)}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex items-center justify-between">
                                                            <span className="font-bold text-gray-800 text-[10px] group-hover:text-indigo-700">
                                                                {item.symbol}
                                                            </span>
                                                            <ExternalLink size={8} className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity" />
                                                        </div>
                                                        <p className="text-[9px] text-gray-600 leading-snug mt-0.5 line-clamp-3">
                                                            {item.insightText}
                                                        </p>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )
                            ))}
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

export default IndexInsightsWidget;

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { MarketIndexData, FiiDiiData, IndexInsightCategory } from '../../types/trackingTypes';
import { addTrackedIndex, removeTrackedIndex, getTrackedItems } from '../../services/trackingStorage';
import { fetchFiiDiiActivity, fetchIndexInsights } from '../../services/dataService';
import {MARKET_OVERVIEW_INDICES} from '../../types/constants.ts'
import { Activity, Search, RefreshCw, CheckSquare, Square, Loader2,TrendingUp,Calendar, DollarSign, ExternalLink } from 'lucide-react';
import IndexInsightsWidget from './IndexInsightsWidget';

interface MarketOverviewProps {
  indicesData: MarketIndexData[];
  trackedIndices: string[];
  onRefresh: () => void;
  loading: boolean;
  onSelectStock?: (symbol: string, name: string) => void;
}

const IndexRow: React.FC<{ 
    data: MarketIndexData, 
    isTracked: boolean, 
    onToggle: () => void,
    isAlternate?: boolean,
    onSelectStock?: (symbol: string, name: string) => void,
    insightData?: IndexInsightCategory[],
    isInsightLoading?: boolean
}> = ({ data, isTracked, onToggle, isAlternate, onSelectStock, insightData, isInsightLoading }) => {

  const isPositive = data.percentChange >= 0;
  const colorClass = isPositive ? 'text-green-600' : 'text-red-600';

  // Calculate 1W return
  const oneWeekReturn = data.oneWeekAgoVal 
    ? ((data.last - data.oneWeekAgoVal) / data.oneWeekAgoVal * 100).toFixed(2) 
    : '-';

  // Breadth
  const advances = parseInt(data.advances || "0", 10);
  const declines = parseInt(data.declines || "0", 10);
  const total = advances + declines;
  const advanceWidth = total > 0 ? (advances / total) * 100 : 50;

  // 52 Week Range
  const rangePos = data.yearHigh && data.yearLow
    ? ((data.last - data.yearLow) / (data.yearHigh - data.yearLow)) * 100
    : 0;

  return (
    <tr className={`hover:bg-indigo-50/30 transition-colors border-b border-gray-50 group ${isAlternate ? 'bg-gray-50/30' : ''} ${isTracked ? 'bg-indigo-50/10' : ''}`}>
        {/* Track Checkbox */}
        <td className="px-4 py-3">
            <button 
                onClick={(e) => { e.stopPropagation(); onToggle(); }}
                className={`transition-colors ${isTracked ? 'text-indigo-600' : 'text-gray-300 group-hover:text-gray-400'}`}
                title={isTracked ? "Remove from Watchlist" : "Add to Watchlist"}
            >
                {isTracked ? <CheckSquare size={18} /> : <Square size={18} />}
            </button>
        </td>

        <td className="px-4 py-3">
            <div className="flex items-center">
                <span className="font-semibold text-gray-800 text-xs sm:text-sm">{data.index}</span>
                {/* Integrate Insights Widget */}
                {onSelectStock && (
                    <IndexInsightsWidget 
                        indexName={data.index} 
                        onSelectStock={onSelectStock}
                        preloadedData={insightData}
                        isLoading={isInsightLoading}
                    />
                )}
            </div>
        </td>
        <td className="px-4 py-3 text-right font-mono text-gray-700">{data.last.toLocaleString()}</td>
        <td className={`px-4 py-3 text-right font-medium ${colorClass}`}>
            {isPositive ? '+' : ''}{data.percentChange.toFixed(2)}%
        </td>

        {/* Valuation (PE | PB | DY) */}
        <td className="px-4 py-3 text-center text-gray-600 hidden sm:table-cell">
            <div className="flex items-center justify-center gap-2 text-[11px]">
                <span className="font-medium bg-gray-100 px-1.5 py-0.5 rounded text-gray-700" title="P/E">{data.pe || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="P/B">{data.pb || '-'}</span>
                <span className="text-gray-300">|</span>
                <span className="text-gray-500" title="Yield">{data.dy || '-'}</span>
            </div>
        </td>

        {/* Returns */}
        <td className="px-4 py-3 text-center hidden md:table-cell">
            <div className="flex items-center justify-center gap-3 text-[11px]">
                <div className="flex flex-col items-center w-8">
                    <span className={parseFloat(oneWeekReturn) >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {oneWeekReturn}%
                    </span>
                    <span className="text-[9px] text-gray-400">1W</span>
                </div>
                <div className="flex flex-col items-center w-8">
                    <span className={data.perChange30d >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {data.perChange30d.toFixed(1)}%
                    </span>
                    <span className="text-[9px] text-gray-400">1M</span>
                </div>
                <div className="flex flex-col items-center w-8">
                    <span className={data.perChange365d >= 0 ? 'text-green-600 font-medium' : 'text-red-600 font-medium'}>
                        {data.perChange365d.toFixed(1)}%
                    </span>
                    <span className="text-[9px] text-gray-400">1Y</span>
                </div>
            </div>
        </td>

        {/* 52W Range */}
        <td className="px-4 py-3 hidden lg:table-cell">
            <div className="flex flex-col gap-1 w-full max-w-[120px] mx-auto">
                <div className="flex justify-between text-[9px] text-gray-400">
                    <span>{data.yearLow?.toLocaleString()}</span>
                    <span>{data.yearHigh?.toLocaleString()}</span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-1.5 overflow-hidden relative">
                    <div 
                        className="absolute h-full w-1.5 bg-indigo-600 rounded-full top-0 ml-[-3px]" 
                        style={{ left: `${Math.min(Math.max(rangePos, 0), 100)}%` }}
                    ></div>
                </div>
            </div>
        </td>

        {/* Breadth */}
        <td className="px-4 py-3 hidden xl:table-cell">
            <div className="flex flex-col gap-1 w-full max-w-[80px] mx-auto">
                <div className="flex w-full h-1.5 rounded-full overflow-hidden bg-gray-200">
                    <div className="bg-green-500 h-full" style={{ width: `${advanceWidth}%` }}></div>
                    <div className="bg-red-500 h-full" style={{ width: `${100 - advanceWidth}%` }}></div>
                </div>
                <div className="flex justify-between text-[9px]">
                    <span className="text-green-600 font-medium">{advances}</span>
                    <span className="text-red-600 font-medium">{declines}</span>
                </div>
            </div>
        </td>
    </tr>
  );
};

export const MarketOverview: React.FC<MarketOverviewProps> = ({ indicesData, trackedIndices, onRefresh, loading, onSelectStock }) => {
  const [filterQuery, setFilterQuery] = useState('');
  const [fiiData, setFiiData] = useState<FiiDiiData | null>(null);

  // State for Insights
  const [insightsMap, setInsightsMap] = useState<Record<string, IndexInsightCategory[]>>({});
  const [insightsLoading, setInsightsLoading] = useState(false);
  const dataFetchedRef = useRef(false);

  // Use all indices available from the API and filter locally
  const filteredData = useMemo(() => {
      let data = [...indicesData]; // Copy array before sorting

      if (filterQuery) {
          const lowerQ = filterQuery.toLowerCase();
          data = data.filter(i => i.index.toLowerCase().includes(lowerQ));
      }
      else {
          // If not searching, show only Default Overview + Tracked Indices
          data = data.filter(i => 
              MARKET_OVERVIEW_INDICES.includes(i.index) || 
              trackedIndices.includes(i.index)
          );
      }

      // Sort: Tracked first, then by name
      return data.sort((a, b) => {
          const aTracked = trackedIndices.includes(a.index);
          const bTracked = trackedIndices.includes(b.index);
          if (aTracked && !bTracked) return -1;
          if (!aTracked && bTracked) return 1;
          return a.index.localeCompare(b.index);
      });
  }, [indicesData, filterQuery, trackedIndices]);

  useEffect(() => {
      const loadFii = async () => {
          const data = await fetchFiiDiiActivity(false);
          setFiiData(data);
      };
      loadFii();
  }, []);

  // --- Insight Fetching Logic ---
  const fetchInsightsForIndices = async (indices: MarketIndexData[]) => {
      if (indices.length === 0) return;
      setInsightsLoading(true);

      const trackedItems = getTrackedItems();
      const trackedSymbols = new Set(trackedItems.filter(i => i.type === 'STOCK').map(i => i.id));

      try {
          // Process sequentially or small batches to avoid too many requests
          // Given constraints, we'll do simple Promise.all but limited to filteredData
          // We limit to max 10 to avoid hammering proxy if user tracks many indices
          const targets = indices.slice(0, 10);

          const requests = targets.map(async (idx) => {
              try {
                  const rawInsights = await fetchIndexInsights(idx.index);
                  // Filter for tracked stocks
                  const filtered = rawInsights.map(category => ({
                      ...category,
                      items: category.items.filter(item => trackedSymbols.has(item.symbol))
                  })).filter(category => category.items.length > 0);

                  return { index: idx.index, data: filtered };
              } catch (e) {
                  return { index: idx.index, data: [] };
              }
          });

          const results = await Promise.all(requests);
          setInsightsMap(prev => {
              const next = { ...prev };
              results.forEach(res => {
                  next[res.index] = res.data;
              });
              return next;
          });

      } catch (error) {
          console.error("Error fetching overview insights", error);
      } finally {
          setInsightsLoading(false);
      }
  };

  // Fetch insights when data loads or on refresh
  useEffect(() => {
      if (filteredData.length > 0 && !dataFetchedRef.current) {
          fetchInsightsForIndices(filteredData);
          dataFetchedRef.current = true;
      }
  }, [filteredData]);

  const handleRefreshAll = async () => {
      onRefresh(); // Refresh indices
      const data = await fetchFiiDiiActivity(true); // Force refresh FII
      setFiiData(data);
      // Re-fetch insights
      fetchInsightsForIndices(filteredData);
  };

  const handleToggleTrack = (indexName: string) => {
      if (trackedIndices.includes(indexName)) {
          removeTrackedIndex(indexName);
      } else {
          addTrackedIndex(indexName);
      }
  };

  const TableHeader = () => (
      <thead className="bg-gray-50 text-gray-500 text-[10px] uppercase font-bold tracking-wider border-b border-gray-200 sticky top-0 z-10">
          <tr>
              <th className="px-4 py-3 w-10"></th> {/* Checkbox */}
              <th className="px-4 py-3 text-left">Index</th>
              <th className="px-4 py-3 text-right">Price</th>
              <th className="px-4 py-3 text-right">Change</th>
              <th className="px-4 py-3 text-center hidden sm:table-cell">Valuation</th>
              <th className="px-4 py-3 text-center hidden md:table-cell">Returns</th>
              <th className="px-4 py-3 text-center hidden lg:table-cell">52W Range</th>
              <th className="px-4 py-3 text-center hidden xl:table-cell">Breadth</th>
          </tr>
      </thead>
  );

  const formatCurrency = (val: number) => {
      return val.toLocaleString('en-IN', { maximumFractionDigits: 0 });
  };

  return (
    <div className="flex flex-col gap-6 pb-10">
        <div className="space-y-4">
            <div className="flex flex-col sm:flex-row items-center justify-between gap-4">
               <div className="flex items-center gap-4">
                   <div className="flex items-center gap-2">
                       <div className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg">
                          <Activity size={18} />
                       </div>
                       <h3 className="text-lg font-bold text-gray-900">All Market Indices</h3>
                       <span className="text-xs bg-gray-100 text-gray-500 px-2 py-0.5 rounded-full">
                           {filteredData.length}
                       </span>
                   </div>

                   {/* FII/DII Mini Widget */}
                   {fiiData && fiiData.latest && (
                       <div className="relative group hidden md:flex items-center gap-3 px-3 py-1 bg-white border border-gray-200 rounded-lg shadow-sm text-xs cursor-help">
                           <div className="flex items-center gap-1.5">
                               <span className="font-bold text-gray-500">FII</span>
                               <span className={`font-mono font-medium ${fiiData.latest.fiiNet > 0 ? 'text-green-600' : 'text-red-600'}`}>
                                   {fiiData.latest.fiiNet > 0 ? '+' : ''}{formatCurrency(fiiData.latest.fiiNet)}Cr
                               </span>
                           </div>
                           <div className="h-3 w-px bg-gray-200"></div>
                           <div className="flex items-center gap-1.5">
                               <span className="font-bold text-gray-500">DII</span>
                               <span className={`font-mono font-medium ${fiiData.latest.diiNet > 0 ? 'text-green-600' : 'text-red-600'}`}>
                                   {fiiData.latest.diiNet > 0 ? '+' : ''}{formatCurrency(fiiData.latest.diiNet)}Cr
                               </span>
                           </div>
                           <a 
                               href="https://trendlyne.com/macro-data/fii-dii/latest/cash-pastmonth/" 
                               target="_blank" 
                               rel="noreferrer"
                               className="text-gray-400 hover:text-indigo-600"
                           >
                               <ExternalLink size={10} />
                           </a>

                           {/* Tooltip Popover */}
                           <div className="absolute top-full left-0 mt-2 w-64 bg-white border border-gray-200 shadow-xl rounded-lg p-3 z-50 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all">
                               <h4 className="text-[10px] font-bold uppercase text-gray-500 mb-2 border-b border-gray-100 pb-1">Institutional Activity</h4>
                               <div className="space-y-2">
                                   <div className="flex justify-between text-[10px] text-gray-400">
                                       <span>Period</span>
                                       <span className="mr-8">FII</span>
                                       <span>DII</span>
                                   </div>
                                   {/* Latest */}
                                   <div className="flex justify-between text-xs font-mono">
                                       <span className="text-gray-600 w-16 truncate">{fiiData.latest.period.replace('Last ','')}</span>
                                       <span className={`${fiiData.latest.fiiNet > 0 ? 'text-green-600' : 'text-red-600'} w-16 text-right`}>{formatCurrency(fiiData.latest.fiiNet)}</span>
                                       <span className={`${fiiData.latest.diiNet > 0 ? 'text-green-600' : 'text-red-600'} w-16 text-right`}>{formatCurrency(fiiData.latest.diiNet)}</span>
                                   </div>
                                   {/* History */}
                                   {fiiData.history.map((h, idx) => (
                                       <div key={idx} className="flex justify-between text-xs font-mono">
                                            <span className="text-gray-600 w-16 truncate">{h.period.replace('Last ','')}</span>
                                            <span className={`${h.fiiNet > 0 ? 'text-green-600' : 'text-red-600'} w-16 text-right`}>{formatCurrency(h.fiiNet)}</span>
                                            <span className={`${h.diiNet > 0 ? 'text-green-600' : 'text-red-600'} w-16 text-right`}>{formatCurrency(h.diiNet)}</span>
                                       </div>
                                   ))}
                               </div>
                           </div>
                       </div>
                   )}
               </div>

               <div className="flex items-center gap-3 w-full sm:w-auto">
                   <div className="relative flex-1 sm:w-64">
                       <div className="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none">
                           <Search size={14} className="text-gray-400" />
                       </div>
                       <input 
                           type="text"
                           value={filterQuery}
                           onChange={(e) => setFilterQuery(e.target.value)}
                           placeholder="Filter indices..."
                           className="w-full bg-white border border-gray-200 text-gray-700 text-sm rounded-lg pl-9 pr-3 py-1.5 focus:outline-none focus:ring-2 focus:ring-indigo-500"
                       />
                   </div>

                   <button 
                       onClick={handleRefreshAll}
                       disabled={loading}
                       className="p-1.5 bg-white border border-gray-200 text-gray-500 hover:text-indigo-600 hover:border-indigo-200 rounded-lg transition-all disabled:opacity-50"
                       title="Refresh Data"
                   >
                       <RefreshCw size={16} className={loading ? "animate-spin" : ""} />
                   </button>
               </div>
            </div>

            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden flex flex-col max-h-[600px]">
                {loading && indicesData.length === 0 ? (
                    <div className="p-12 flex flex-col items-center justify-center text-gray-400 text-sm italic gap-2">
                        <Loader2 size={24} className="animate-spin text-indigo-500" />
                        Loading market indices...
                    </div>
                ) : filteredData.length > 0 ? (
                    <div className="overflow-auto custom-scrollbar">
                        <table className="w-full text-xs text-left whitespace-nowrap">
                            <TableHeader />
                            <tbody className="bg-white">
                                {filteredData.map((data, idx) => (
                                    <IndexRow 
                                        key={data.index} 
                                        data={data} 
                                        isTracked={trackedIndices.includes(data.index)}
                                        onToggle={() => handleToggleTrack(data.index)}
                                        isAlternate={idx % 2 === 1}
                                        onSelectStock={onSelectStock} 
                                        insightData={insightsMap[data.index]}
                                        isInsightLoading={insightsLoading}
                                    />
                                ))}
                            </tbody>
                        </table>
                    </div>
                ) : (
                    <div className="p-8 text-center text-gray-400 text-sm italic">
                        No indices found matching "{filterQuery}".
                    </div>
                )}
            </div>
        </div>
        {/* Section 2: Portfolio Movers (Placeholder) */}
        <div className="space-y-4 opacity-50 pointer-events-none grayscale">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="p-1.5 bg-gray-100 text-gray-500 rounded-lg">
                        <TrendingUp size={18} />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">Portfolio Movers</h3>
                </div>
                <span className="text-xs bg-gray-100 text-gray-500 px-2 py-1 rounded">Coming Soon</span>
            </div>
            <div className="bg-white p-8 rounded-xl border border-gray-200 text-center">
                <p className="text-gray-400 text-sm">Top gainers, losers, and volume shockers from your tracking list.</p>
            </div>
        </div>

        {/* Section 3: Sectoral Pulse (Placeholder) */}
        <div className="space-y-4 opacity-50 pointer-events-none grayscale">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="p-1.5 bg-gray-100 text-gray-500 rounded-lg">
                        <Calendar size={18} />
                    </div>
                    <h3 className="text-lg font-bold text-gray-900">Sectoral Pulse</h3>
                </div>
                <span className="text-xs bg-gray-100 text-gray-500 px-2 py-1 rounded">Coming Soon</span>
            </div>
            <div className="bg-white p-8 rounded-xl border border-gray-200 text-center">
                <p className="text-gray-400 text-sm">Sector-wise performance and rotation analysis.</p>
        </div>
    </div>
</div>

  );
};

export default MarketOverview;

payload.text:
**Analyzing UI Consistency**

I'm currently investigating why the UI isn't reflecting the addition of new stocks. It seems the "Market Insights" functionality within the `MarketOverview` component is remaining unchanged. I suspect there may be a disconnection between the data updates and the component's refresh mechanism, or perhaps an issue with the data filtering within that specific section of the `MarketOverview`.


**Addressing State Management**

I'm now focusing on ensuring the `IndexInsightsWidget` accurately reflects tracked stocks within an index. I realized the `MarketOverview` wasn't responding to updates in the tracked stock list. Specifically, the component isn't re-fetching insights when a stock is added. My plan involves listening to the `fundflow_tracking_update` event and using this event to re-trigger the necessary data fetches, or recalculations. Furthermore, I must consider `dataFetchedRef.current`, to prevent unintended side effects.


**Implementing Data Caching**

I've decided to optimize the `fetchIndexInsights` process. Instead of refetching everything when the filter changes (tracked stocks), I'll cache the raw insights in a `rawInsightsMap`. Then, I'll filter them locally. This will involve implementing a `recalculateFilteredInsights` function triggered by a `useEffect` hook listening to `fundflow_tracking_update`. This should improve efficiency.


**Refining Prop Handling**

I've zeroed in on the `MarketOverview`'s prop handling. It turns out the component receives `trackedIndices` but insights rely on `trackedStocks`. I'm going to alter the `useEffect` to trigger based on changes to `trackedStocks` rather than just `filteredData`. I'll focus on getting the correct stocks, rather than entire indices. I am now simplifying the data fetches.


**Optimizing Data Flow**

My focus is now on streamlining the data flow within `MarketOverview`. The key is separating raw data fetching from user-specific filtering. I'll store `rawInsights` in state, fetched on mount, and re-fetched periodically. Then I'll filter the data locally to compute `filteredInsights`, which the child components consume, triggered by changes in either `rawInsights` or `trackedItems`. I've added a listener for `fundflow_tracking_update` to update the local `trackedItems` state and re-trigger filtering for improved responsiveness. I am dropping `dataFetchedRef` logic, so an update always re-triggers.


**Refactoring Insights Flow**

