    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    if (isOpen) document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const handleToggle = async (e: React.MouseEvent) => {
      e.stopPropagation();

      // If controlled by parent (preloadedData provided), just toggle
      if (preloadedData !== undefined) {
          if (data.length > 0) setIsOpen(!isOpen);
          return;
      }

      // Legacy/Self-managed mode (fetch on click)
      if (!isOpen && data.length === 0) {
          setLocalLoading(true);
          setIsOpen(true);

          try {
              const insights = await fetchIndexInsights(indexName);
              const trackedItems = getTrackedItems();
