export const MarketOverview: React.FC<MarketOverviewProps> = ({ indicesData, trackedIndices, onRefresh, loading, onSelectStock }) => {
  const [filterQuery, setFilterQuery] = useState('');
  const [fiiData, setFiiData] = useState<FiiDiiData | null>(null);

  // State for Insights
  const [filteredInsightsMap, setFilteredInsightsMap] = useState<Record<string, IndexInsightCategory[]>>({});
  const [insightsLoading, setInsightsLoading] = useState(false);

  // Store raw insights to avoid re-fetching when only filter changes
  const rawInsightsRef = useRef<Record<string, IndexInsightCategory[]>>({});

  // Tick to force re-filtering when tracking list updates
  const [trackingTick, setTrackingTick] = useState(0);

  // Use all indices available from the API and filter locally
  const filteredData = useMemo(() => {
      let data = [...indicesData]; // Copy array before sorting

      if (filterQuery) {
          const lowerQ = filterQuery.toLowerCase();
          data = data.filter(i => i.index.toLowerCase().includes(lowerQ));
      }
      else {
          // If not searching, show only Default Overview + Tracked Indices
          data = data.filter(i => 
              MARKET_OVERVIEW_INDICES.includes(i.index) || 
              trackedIndices.includes(i.index)
          );
      }

      // Sort: Tracked first, then by name
      return data.sort((a, b) => {
          const aTracked = trackedIndices.includes(a.index);
          const bTracked = trackedIndices.includes(b.index);
          if (aTracked && !bTracked) return -1;
          if (!aTracked && bTracked) return 1;
          return a.index.localeCompare(b.index);
      });
  }, [indicesData, filterQuery, trackedIndices]);

  useEffect(() => {
      const loadFii = async () => {
          const data = await fetchFiiDiiActivity(false);
          setFiiData(data);
      };
      loadFii();
  }, []);

  // Listen for tracking updates globally
  useEffect(() => {
      const handleUpdate = () => {
          setTrackingTick(prev => prev + 1);
      };
      window.addEventListener('fundflow_tracking_update', handleUpdate);
      return () => window.removeEventListener('fundflow_tracking_update', handleUpdate);
  }, []);

  // --- Insight Fetching Logic (Raw Data) ---
  useEffect(() => {
      // Only fetch if we have indices
      if (filteredData.length === 0) return;

      const fetchRaw = async () => {
          setInsightsLoading(true);

          // Identify indices that need fetching (not in ref)
          // We limit to top 10 visible for performance, or all if feasible.
          // Let's do top 12 to cover standard grid
          const targets = filteredData.slice(0, 12); 
          const missing = targets.filter(t => !rawInsightsRef.current[t.index]);

          if (missing.length > 0) {
              const results = await Promise.all(missing.map(async (idx) => {
                  try {
                      const data = await fetchIndexInsights(idx.index);
                      return { index: idx.index, data };
                  } catch {
                      return { index: idx.index, data: [] };
                  }
              }));

              results.forEach(res => {
                  rawInsightsRef.current[res.index] = res.data;
              });
          }

          // Trigger filtering after fetch
          setTrackingTick(prev => prev + 1);
          setInsightsLoading(false);
      };

      fetchRaw();
  }, [filteredData]); // Runs when indices change (e.g. initial load or search)

  // --- Insight Filtering Logic (Local) ---
  useEffect(() => {
      const trackedItems = getTrackedItems();
      const trackedSymbols = new Set(trackedItems.filter(i => i.type === 'STOCK').map(i => i.id));

      const newFiltered: Record<string, IndexInsightCategory[]> = {};

      Object.keys(rawInsightsRef.current).forEach(indexName => {
          const categories = rawInsightsRef.current[indexName];

          const filteredCategories = categories.map(cat => ({
              ...cat,
              // Filter items within category that match tracked symbols
              items: cat.items.filter(item => trackedSymbols.has(item.symbol))
          })).filter(cat => cat.items.length > 0); // Only keep categories with items

          if (filteredCategories.length > 0) {
              newFiltered[indexName] = filteredCategories;
          }
      });

      setFilteredInsightsMap(newFiltered);
  }, [trackingTick]); // Runs when data is fetched OR when tracking updates

  const handleRefreshAll = async () => {
      onRefresh(); // Refresh indices
      const data = await fetchFiiDiiActivity(true); // Force refresh FII
      setFiiData(data);
      // Clear cache to force refetch of insights
      rawInsightsRef.current = {};
      setTrackingTick(prev => prev + 1); // Trigger fetch effect implicitly via state reset/refresh
  };

  const handleToggleTrack = (indexName: string) => {
      if (trackedIndices.includes(indexName)) {
          removeTrackedIndex(indexName);
      } else {
          addTrackedIndex(indexName);
      }
  };

  const TableHeader = () => (
      <thead className="bg-gray-50 text-gray-500 text-[10px] uppercase font-bold tracking-wider border-b border-gray-200 sticky top-0 z-10">
          <tr>
              <th className="px-4 py-3 w-10"></th> {/* Checkbox */}
              <th className="px-4 py-3 text-left">Index</th>
              <th className="px-4 py-3 text-right">Price</th>
              <th className="px-4 py-3 text-right">Change</th>
              <th className="px-4 py-3 text-center hidden sm:table-cell">Valuation</th>
              <th className="px-4 py-3 text-center hidden md:table-cell">Returns</th>
              <th className="px-4 py-3 text-center hidden lg:table-cell">52W Range</th>
              <th className="px-4 py-3 text-center hidden xl:table-cell">Breadth</th>
          </tr>
      </thead>
  );

  const formatCurrency = (val: number) => {
