import React, { useState, useRef, useEffect } from 'react';
import { Lightbulb, Loader2, X, TrendingUp, TrendingDown, Minus, ExternalLink } from 'lucide-react';
import { fetchIndexInsights } from '../../services/dataService';
import { IndexInsightCategory } from '../../types/trackingTypes';
import { getTrackedItems } from '../../services/trackingStorage';

interface IndexInsightsWidgetProps {
  indexName: string;
  onSelectStock: (symbol: string, name: string) => void;
}

const IndexInsightsWidget: React.FC<IndexInsightsWidgetProps> = ({ 
    indexName, 
    onSelectStock
}) => {
  const [isOpen, setIsOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [data, setData] = useState<IndexInsightCategory[]>([]);
  const [hasFetched, setHasFetched] = useState(false); // Track if data has been fetched at least once
  const popoverRef = useRef<HTMLDivElement>(null);

  // Close on click outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (popoverRef.current && !popoverRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    if (isOpen) document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [isOpen]);

  const handleToggle = async (e: React.MouseEvent) => {
      e.stopPropagation();

      if (!isOpen) {
          // If not yet fetched or if we want to re-open
          setIsOpen(true);

          // Only fetch if we haven't fetched yet
          if (!hasFetched) {
              setIsLoading(true);
              try {
                  const insights = await fetchIndexInsights(indexName);
                  const trackedItems = getTrackedItems();
                  const trackedSymbols = new Set(trackedItems.filter(i => i.type === 'STOCK').map(i => i.id));

                  const filteredInsights = insights.map(category => ({
                      ...category,
                      items: category.items.filter(item => trackedSymbols.has(item.symbol))
                  })).filter(category => category.items.length > 0);

                  setData(filteredInsights);
                  setHasFetched(true);
              } catch (error) {
                  console.error("Failed to fetch insights", error);
              } finally {
                  setIsLoading(false);
              }
          }
      } else {
          setIsOpen(false);
      }
  };

  const totalInsights = data.reduce((acc, cat) => acc + cat.items.length, 0);

  const getIcon = (type: string) => {
      if (type === 'positive') return <TrendingUp size={14} className="text-green-600" />;
      if (type === 'negative') return <TrendingDown size={14} className="text-red-600" />;
      return <Minus size={14} className="text-gray-400" />;
  };

  return (
    <div className="relative inline-block ml-2" ref={popoverRef}>
        <button 
            onClick={handleToggle}
            // Disable if loading
            disabled={isLoading}
            className={`flex items-center gap-1.5 px-2 py-0.5 rounded-full text-[10px] font-bold transition-all shadow-sm ${
                isOpen 
                ? 'bg-indigo-600 text-white' 
                : hasFetched && totalInsights > 0 
                    ? 'bg-indigo-100 text-indigo-700 hover:bg-indigo-200 border border-indigo-200'
                    : 'bg-gray-50 text-gray-400 border border-gray-100 hover:bg-gray-100'
            }`}
            title="Insights for Tracked Stocks"
        >
            {isLoading ? (
                <Loader2 size={10} className="animate-spin" />
            ) : (
                <Lightbulb size={10} className={hasFetched && totalInsights > 0 ? "fill-indigo-700" : ""} />
            )}

            {/* Show count only if fetched */}
            {hasFetched && !isLoading ? totalInsights : ''}
        </button>

        {isOpen && (
            <div className="absolute z-50 mt-2 w-96 bg-white border border-gray-200 shadow-xl rounded-xl overflow-hidden left-0 top-full animate-fade-in origin-top-left">
                <div className="bg-gray-50 px-4 py-2 border-b border-gray-100 flex items-center justify-between">
                    <h4 className="font-bold text-gray-800 text-xs">Insights for {indexName}</h4>
                    <button 
                        onClick={() => setIsOpen(false)}
                        className="text-gray-400 hover:text-gray-600 p-1 rounded-full hover:bg-gray-200 transition-colors"
                    >
                        <X size={14} />
                    </button>
                </div>

                <div className="max-h-80 overflow-y-auto custom-scrollbar p-2">
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center py-6 text-gray-400 gap-2">
                            <Loader2 size={20} className="animate-spin text-indigo-500" />
                            <span className="text-xs">Updating...</span>
                        </div>
                    ) : totalInsights === 0 ? (
                        <div className="p-4 text-center text-xs text-gray-400 italic">
                            No active insights for your tracked stocks in this index.
                        </div>
                    ) : (
                        <div className="space-y-3">
                            {data.map(category => (
                                category.items.length > 0 && (
                                    <div key={category.id}>
                                        <h5 className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-1.5 ml-1 border-b border-gray-100 pb-1">
                                            {category.title}
                                        </h5>
                                        <div className="space-y-1.5">
                                            {category.items.map((item, idx) => (
                                                <div 
                                                    key={`${category.id}-${idx}`}
                                                    onClick={() => {
                                                        if (onSelectStock) {
                                                            onSelectStock(item.symbol, item.symbol);
                                                        }
                                                        setIsOpen(false);
                                                    }}
                                                    className="group flex gap-3 p-2.5 rounded-lg hover:bg-indigo-50 border border-gray-100 hover:border-indigo-100 cursor-pointer transition-all items-start bg-white"
                                                >
                                                    <div className={`mt-0.5 shrink-0 bg-gray-50 p-1 rounded-md border border-gray-100`}>
                                                        {getIcon(item.type)}
                                                    </div>
                                                    <div className="flex-1 min-w-0">
                                                        <div className="flex items-center justify-between mb-1">
                                                            <span className="font-bold text-gray-800 text-xs group-hover:text-indigo-700 underline decoration-dotted decoration-gray-300">
                                                                {item.symbol}
                                                            </span>
                                                            <ExternalLink size={10} className="text-gray-300 opacity-0 group-hover:opacity-100 transition-opacity" />
                                                        </div>
                                                        {/* Full text wrap enabled */}
                                                        <p className="text-[11px] text-gray-600 leading-relaxed break-words whitespace-normal">
                                                            {item.insightText}
                                                        </p>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                )
                            ))}
                        </div>
                    )}
                </div>
            </div>
        )}
    </div>
  );
};

